import yahooFinance from 'yahoo-finance2';

export interface YahooFinanceData {
  quote: any;
  summaryProfile: any;
  financialData: any;
  defaultKeyStatistics: any;
}

export async function getCompanyData(ticker: string): Promise<YahooFinanceData> {
  try {
    // Suppress warnings from yahoo-finance2
    yahooFinance.suppressNotices(['yahooSurvey']);

    const [quote, summaryProfile, financialData, defaultKeyStatistics] = await Promise.all([
      yahooFinance.quote(ticker),
      yahooFinance.quoteSummary(ticker, { modules: ['summaryProfile'] }),
      yahooFinance.quoteSummary(ticker, { modules: ['financialData'] }),
      yahooFinance.quoteSummary(ticker, { modules: ['defaultKeyStatistics'] })
    ]);

    return {
      quote,
      summaryProfile: summaryProfile.summaryProfile,
      financialData: financialData.financialData,
      defaultKeyStatistics: defaultKeyStatistics.defaultKeyStatistics
    };
  } catch (error) {
    console.error(`Error fetching Yahoo Finance data for ${ticker}:`, error);
    throw new Error(`Failed to fetch financial data for ticker: ${ticker}`);
  }
}

import { NewsHeadline } from '../types';

export async function getCompanyNews(companyName: string, ticker: string): Promise<NewsHeadline[]> {
  try {
    const apiKey = process.env.NEWS_API_KEY;

    // If no API key, return mock news to allow the app to run without NewsAPI credentials
    if (!apiKey) {
      console.warn('NEWS_API_KEY not found. Returning fallback news data.');
      return getMockNews(companyName, ticker);
    }

    const query = encodeURIComponent(`"${companyName}" OR "${ticker}"`);
    const response = await fetch(`https://newsapi.org/v2/everything?q=${query}&sortBy=publishedAt&language=en&pageSize=10`, {
      headers: {
        'X-Api-Key': apiKey
      }
    });

    if (!response.ok) {
      throw new Error(`News API responded with status: ${response.status}`);
    }

    const data = await response.json();

    return data.articles.map((article: any) => ({
      title: article.title,
      source: article.source.name,
      date: new Date(article.publishedAt).toISOString().split('T')[0],
      url: article.url,
      // Sentiment will be determined later by the LLM agent
      sentiment: 'neutral' 
    }));
  } catch (error) {
    console.error(`Error fetching news for ${companyName}:`, error);
    // Graceful degradation: return mock data rather than failing the whole report
    return getMockNews(companyName, ticker);
  }
}

function getMockNews(companyName: string, ticker: string): NewsHeadline[] {
  const today = new Date();
  const formatDate = (daysAgo: number) => {
    const d = new Date(today);
    d.setDate(d.getDate() - daysAgo);
    return d.toISOString().split('T')[0];
  };

  return [
    { title: `${companyName} Announces Upcoming Earnings Call`, source: 'Financial Times', sentiment: 'neutral', date: formatDate(1) },
    { title: `Analysts upgrade ${ticker} price target citing strong demand`, source: 'Reuters', sentiment: 'positive', date: formatDate(2) },
    { title: `Market headwinds could impact ${companyName} next quarter`, source: 'Bloomberg', sentiment: 'negative', date: formatDate(3) },
    { title: `${companyName} unveils new strategic initiatives for 2026`, source: 'Wall Street Journal', sentiment: 'positive', date: formatDate(4) },
    { title: `Sector rotation shows investors moving away from ${ticker}`, source: 'CNBC', sentiment: 'negative', date: formatDate(5) }
  ];
}

import OpenAI from 'openai';

// Ensure the application doesn't crash on boot if the key is missing, 
// but throw errors when actually trying to use the client.
export function getLLMClient() {
  if (!process.env.OPENAI_API_KEY) {
    console.warn("OPENAI_API_KEY environment variable is missing.");
  }

  return new OpenAI({
    apiKey: process.env.OPENAI_API_KEY || 'dummy-key',
  });
}

export async function askLLM<T>(
  systemPrompt: string, 
  userPrompt: string, 
  responseFormat?: any
): Promise<T> {
  const openai = getLLMClient();

  try {
    const response = await openai.chat.completions.create({
      model: "gpt-4o", // Using GPT-4o as per architecture doc
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt }
      ],
      response_format: responseFormat ? { type: "json_object" } : undefined,
      temperature: 0.2, // Low temperature for more analytical/consistent responses
    });

    const content = response.choices[0].message.content || "{}";

    if (responseFormat) {
      return JSON.parse(content) as T;
    }

    return content as unknown as T;
  } catch (error) {
    console.error("Error communicating with LLM:", error);
    throw new Error("Failed to process analysis through AI model.");
  }
}

