import { AgentState } from "../state";
import { getGeminiModel } from "../llm";
import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { StructuredOutputParser } from "langchain/output_parsers";
import { z } from "zod";

const sentimentSchema = z.object({
  overallSentiment: z.enum(["Bullish", "Bearish", "Neutral"]).describe("The overall sentiment of the news"),
  sentimentScore: z.number().min(0).max(100).describe("A sentiment score from 0 (very bearish) to 100 (very bullish)"),
  positiveDevelopments: z.array(z.string()).describe("List of key positive developments"),
  negativeDevelopments: z.array(z.string()).describe("List of key negative developments or risks"),
  analyzedHeadlines: z.array(z.object({
    title: z.string(),
    sentiment: z.enum(["positive", "negative", "neutral"])
  })).describe("The same headlines mapped with their individual sentiment")
});

export const newsAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  console.log(`[News Agent] Fetching news for ${state.ticker}`);

  try {
    const apiKey = process.env.NEWS_API_KEY;
    let rawHeadlines: Array<{title: string, source: string, date: string}> = [];

    // Fetch real news
    if (apiKey) {
      const query = encodeURIComponent(`"${state.companyOverview?.name || state.ticker}" OR "${state.ticker}"`);
      const res = await fetch(`https://newsapi.org/v2/everything?q=${query}&sortBy=publishedAt&language=en&pageSize=10`, {
        headers: { 'X-Api-Key': apiKey }
      });
      if (res.ok) {
        const data = await res.json();
        rawHeadlines = data.articles.map((a: any) => ({
          title: a.title,
          source: a.source.name,
          date: new Date(a.publishedAt).toISOString().split('T')[0]
        }));
      }
    }

    // Fallback if no API key or fetch fails
    if (rawHeadlines.length === 0) {
      console.warn("[News Agent] Using fallback news (API key missing or request failed)");
      rawHeadlines = [
        { title: `${state.ticker} announces strategic expansion and new product lines`, source: 'Reuters', date: new Date().toISOString() },
        { title: `Market headwinds affect ${state.ticker} sector projections`, source: 'Bloomberg', date: new Date().toISOString() },
        { title: `Analysts remain cautious on ${state.ticker} near-term guidance`, source: 'CNBC', date: new Date().toISOString() },
        { title: `${state.ticker} beats quarterly expectations`, source: 'Financial Times', date: new Date().toISOString() },
        { title: `Regulatory scrutiny increases for ${state.companyOverview?.industry || 'the industry'}`, source: 'Wall Street Journal', date: new Date().toISOString() }
      ];
    }

    const model = getGeminiModel(0.2);
    const parser = StructuredOutputParser.fromZodSchema(sentimentSchema);

    const newsContext = JSON.stringify(rawHeadlines, null, 2);

    const response = await model.invoke([
      new SystemMessage("You are an expert market sentiment analyst. Analyze recent news headlines for a company, determine the overall sentiment, extract key positive/negative developments, and score the sentiment (0-100)."),
      new HumanMessage(`Analyze these recent headlines for ${state.companyOverview?.name || state.ticker}:\n\n${newsContext}\n\n${parser.getFormatInstructions()}`)
    ]);

    const result = await parser.parse(response.content as string);

    // Merge the AI sentiment back with the raw headline data (source, date)
    const finalHeadlines = rawHeadlines.map((raw, idx) => {
      // Find matching analyzed headline or default to neutral
      const analyzed = result.analyzedHeadlines.find(a => a.title === raw.title) || result.analyzedHeadlines[idx];
      return {
        title: raw.title,
        source: raw.source,
        date: raw.date,
        sentiment: analyzed?.sentiment || "neutral"
      };
    });

    return {
      newsData: {
        overallSentiment: result.overallSentiment,
        sentimentScore: result.sentimentScore,
        positiveDevelopments: result.positiveDevelopments,
        negativeDevelopments: result.negativeDevelopments,
        headlines: finalHeadlines
      },
      messages: [new SystemMessage(`News sentiment analysis completed for ${state.ticker}`)]
    };
  } catch (error: any) {
    console.error("[News Agent] Error:", error);
    return { error: `News Agent failed: ${error.message}` };
  }
};

