import { AgentState } from "../state";
import { getGeminiModel } from "../llm";
import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { StructuredOutputParser } from "langchain/output_parsers";
import { z } from "zod";
import { ResearchReport, ScoreCardData, RiskFactor } from "../../types";

const decisionSchema = z.object({
  recommendation: z.enum(["STRONG BUY", "BUY", "HOLD", "SELL", "STRONG SELL"]).describe("The final investment recommendation"),
  confidenceScore: z.number().min(0).max(100).describe("Confidence in this recommendation (0-100)"),
  targetPrice: z.number().describe("The projected 12-month target price"),
  reasoning: z.string().describe("A comprehensive investment thesis synthesizing all data (3-4 paragraphs)"),
});

export const decisionAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  console.log(`[Decision Agent] Generating recommendation for ${state.ticker}`);

  if (!state.companyOverview || !state.financialData || !state.newsData || !state.riskData) {
    return { error: "Decision Agent missing required previous state data" };
  }

  try {
    const model = getGeminiModel(0.2);
    const parser = StructuredOutputParser.fromZodSchema(decisionSchema);

    const context = `
Company: ${state.companyOverview.name} (${state.ticker})
Current Price: $${state.financialData.currentPrice}
Financial Health Score: ${state.financialData.metrics.healthScore}/100
Revenue Growth: ${state.financialData.metrics.revenueGrowth}
Profitability: ${state.financialData.metrics.profitability}
Overall Sentiment: ${state.newsData.overallSentiment} (Score: ${state.newsData.sentimentScore}/100)
Key Risks: ${state.riskData.marketRisks.concat(state.riskData.competitionRisks).join("; ")}
    `;

    const response = await model.invoke([
      new SystemMessage("You are a Lead Portfolio Manager. Synthesize the findings from your research, financial, sentiment, and risk analysts to make a final investment recommendation. Provide a target price and detailed investment thesis."),
      new HumanMessage(`Generate the final investment decision for ${state.ticker} based on this summary:\n\n${context}\n\n${parser.getFormatInstructions()}`)
    ]);

    const result = await parser.parse(response.content as string);

    // Map LangGraph State to Frontend ResearchReport format
    const scores: ScoreCardData[] = [
      { label: "Financial Health", score: state.financialData.metrics.healthScore, description: state.financialData.metrics.profitability.substring(0, 80) + '...', icon: "DollarSign", color: "green" },
      { label: "Market Sentiment", score: state.newsData.sentimentScore, description: state.newsData.overallSentiment + " based on recent news", icon: "TrendingUp", color: "blue" },
      { label: "Industry Position", score: 85, description: state.companyOverview.industry + " positioning", icon: "Building2", color: "cyan" }, // Hardcoded or estimated score since not strictly defined
      { label: "Risk Score", score: 100 - (state.riskData.marketRisks.length * 10), description: "Based on identified market and regulatory risks", icon: "ShieldCheck", color: "yellow" },
    ];

    const riskFactors: RiskFactor[] = [
      ...state.riskData.marketRisks.map(r => ({ category: "Market", level: "Medium" as const, description: r })),
      ...state.riskData.competitionRisks.map(r => ({ category: "Competition", level: "High" as const, description: r })),
      ...state.riskData.regulatoryRisks.map(r => ({ category: "Regulatory", level: "Medium" as const, description: r })),
    ].slice(0, 5); // Limit to top 5

    const finalReport: ResearchReport = {
      company: {
        name: state.companyOverview.name,
        ticker: state.ticker,
        sector: state.companyOverview.sector,
        industry: state.companyOverview.industry,
        marketCap: state.financialData.marketCap,
        currentPrice: state.financialData.currentPrice,
        priceChange: state.financialData.priceChange,
        priceChangePercent: state.financialData.priceChangePercent,
      },
      recommendation: result.recommendation,
      confidenceScore: result.confidenceScore,
      targetPrice: result.targetPrice,
      scores,
      financialMetrics: [
        { label: "Revenue Growth", value: state.financialData.metrics.revenueGrowth },
        { label: "Profitability", value: state.financialData.metrics.profitability },
        { label: "Debt Analysis", value: state.financialData.metrics.debtAnalysis },
      ],
      sentimentData: {
        overall: state.newsData.overallSentiment,
        score: state.newsData.sentimentScore,
        sources: state.newsData.headlines.length,
        positiveCount: state.newsData.headlines.filter(h => h.sentiment === "positive").length,
        negativeCount: state.newsData.headlines.filter(h => h.sentiment === "negative").length,
        neutralCount: state.newsData.headlines.filter(h => h.sentiment === "neutral").length,
        headlines: state.newsData.headlines
      },
      riskFactors,
      industryAnalysis: state.companyOverview.description + "\n\nCompetitors: " + state.companyOverview.competitors.join(", ") + "\n\nBusiness Model: " + state.companyOverview.businessModel,
      financialAnalysis: state.financialData.rawAnalysis,
      riskAnalysis: state.riskData.rawAnalysis,
      investmentThesis: result.reasoning,
      generatedAt: new Date().toISOString(),
    };

    return {
      decisionData: result,
      finalReport,
      messages: [new SystemMessage(`Final decision generated for ${state.ticker}`)]
    };
  } catch (error: any) {
    console.error("[Decision Agent] Error:", error);
    return { error: `Decision Agent failed: ${error.message}` };
  }
};

import { StateGraph, START, END } from "@langchain/langgraph";
import { AgentState } from "./state";
import { researchAgent } from "./agents/research-agent";
import { financialAgent } from "./agents/financial-agent";
import { newsAgent } from "./agents/news-agent";
import { riskAgent } from "./agents/risk-agent";
import { decisionAgent } from "./agents/decision-agent";

// Define the state channels
const agentStateChannels = {
  ticker: {
    value: (x: string, y: string) => y ?? x,
    default: () => ""
  },
  companyOverview: {
    value: (x: any, y: any) => y ?? x,
  },
  financialData: {
    value: (x: any, y: any) => y ?? x,
  },
  newsData: {
    value: (x: any, y: any) => y ?? x,
  },
  riskData: {
    value: (x: any, y: any) => y ?? x,
  },
  decisionData: {
    value: (x: any, y: any) => y ?? x,
  },
  finalReport: {
    value: (x: any, y: any) => y ?? x,
  },
  messages: {
    value: (x: any[], y: any[]) => x.concat(y ?? []),
    default: () => []
  },
  error: {
    value: (x: string, y: string) => y ?? x,
  }
};

// Routing logic to halt on error
function shouldContinue(state: AgentState) {
  if (state.error) {
    return END;
  }
  return "continue";
}

// Build the workflow
const workflow = new StateGraph<AgentState>({ channels: agentStateChannels as any })
  .addNode("researchAgent", researchAgent)
  .addNode("financialAgent", financialAgent)
  .addNode("newsAgent", newsAgent)
  .addNode("riskAgent", riskAgent)
  .addNode("decisionAgent", decisionAgent)

  // Define edges (Sequential Workflow)
  .addEdge(START, "researchAgent")

  .addConditionalEdges("researchAgent", (state) => state.error ? END : "financialAgent")
  .addConditionalEdges("financialAgent", (state) => state.error ? END : "newsAgent")
  .addConditionalEdges("newsAgent", (state) => state.error ? END : "riskAgent")
  .addConditionalEdges("riskAgent", (state) => state.error ? END : "decisionAgent")

  .addEdge("decisionAgent", END);

export const app = workflow.compile();

import { NextResponse } from "next/server";
import { app } from "@/lib/langgraph/graph";

export const maxDuration = 300; // Allow 5 minutes for the agents to run sequentially

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { ticker } = body;

    if (!ticker) {
      return NextResponse.json({ error: "Ticker is required" }, { status: 400 });
    }

    console.log(`Starting Research Graph for ${ticker}...`);

    const initialState = {
      ticker: ticker.toUpperCase(),
      messages: [],
    };

    // Execute the compiled LangGraph workflow
    const finalState = await app.invoke(initialState);

    if (finalState.error) {
      console.error("Graph execution error:", finalState.error);
      return NextResponse.json({ error: finalState.error }, { status: 500 });
    }

    if (!finalState.finalReport) {
      return NextResponse.json({ error: "Failed to generate final report" }, { status: 500 });
    }

    return NextResponse.json(finalState.finalReport);

  } catch (error: any) {
    console.error("API Route Error:", error);
    return NextResponse.json(
      { error: "Internal server error during research processing", details: error.message },
      { status: 500 }
    );
  }
}

