"use client";

import { useState, useCallback, useRef } from "react";
import type { ResearchState, AgentProgress } from "@/lib/types";

const initialAgents: AgentProgress[] = [
  { name: "Research Agent", status: "idle", description: "Analyzing company overview, industry, and competitors", progress: 0, icon: "Search" },
  { name: "Financial Analyst", status: "idle", description: "Evaluating revenue growth, profitability, and debt", progress: 0, icon: "TrendingUp" },
  { name: "Sentiment Analyst", status: "idle", description: "Scanning news and market sentiment", progress: 0, icon: "Newspaper" },
  { name: "Risk Analyst", status: "idle", description: "Evaluating market, competition, and regulatory risks", progress: 0, icon: "ShieldAlert" },
  { name: "Investment Decision Agent", status: "idle", description: "Synthesizing data for final recommendation", progress: 0, icon: "Lightbulb" }
];

export function useResearch() {
  const [state, setState] = useState<ResearchState>({
    status: "idle",
    agents: [],
    report: null,
    error: null,
  });

  const timersRef = useRef<NodeJS.Timeout[]>([]);

  const clearAllTimers = useCallback(() => {
    timersRef.current.forEach(clearTimeout);
    timersRef.current = [];
  }, []);

  const startResearch = useCallback(
    async (query: string) => {
      clearAllTimers();

      // Reset to researching state
      setState({
        status: "researching",
        agents: initialAgents.map((a) => ({ ...a, status: "idle", progress: 0 })),
        report: null,
        error: null,
      });

      // Simulate UI progress while waiting for the actual API
      // We will slowly progress the agents up to 90%, and snap to 100% when API returns
      const agentCount = initialAgents.length;

      for (let i = 0; i < agentCount; i++) {
        const startTimer = setTimeout(() => {
          setState((prev) => ({
            ...prev,
            agents: prev.agents.map((a, idx) =>
              idx === i ? { ...a, status: "running" as const, progress: 10 } : a
            ),
          }));
        }, i * 1500); // Start next agent every 1.5s visually
        timersRef.current.push(startTimer);

        // Slowly increment progress up to 90%
        const progressTimer = setInterval(() => {
          setState((prev) => {
            const currentAgent = prev.agents[i];
            if (currentAgent.status === "running" && currentAgent.progress < 90) {
              return {
                ...prev,
                agents: prev.agents.map((a, idx) =>
                  idx === i ? { ...a, progress: a.progress + 5 } : a
                ),
              };
            }
            return prev;
          });
        }, 800);
        timersRef.current.push(progressTimer);
      }

      try {
        // Actually call the real LangGraph backend
        const response = await fetch("/api/research", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ ticker: query }),
        });

        if (!response.ok) {
          const errData = await response.json().catch(() => ({}));
          throw new Error(errData.error || `HTTP error! status: ${response.status}`);
        }

        const report = await response.json();

        // Clear simulation timers
        clearAllTimers();

        // Snap all agents to completed
        setState((prev) => ({
          ...prev,
          status: "completed",
          agents: prev.agents.map(a => ({ ...a, status: "completed", progress: 100 })),
          report,
          error: null,
        }));

      } catch (error: any) {
        clearAllTimers();
        console.error("Research failed:", error);

        // Mark currently running agents as failed
        setState((prev) => ({
          ...prev,
          status: "error",
          agents: prev.agents.map(a => 
            a.status === "running" || a.status === "idle" ? { ...a, status: "failed" } : a
          ),
          error: error.message || "An unknown error occurred during research",
        }));
      }
    },
    [clearAllTimers]
  );

  const reset = useCallback(() => {
    clearAllTimers();
    setState({
      status: "idle",
      agents: [],
      report: null,
      error: null,
    });
  }, [clearAllTimers]);

  return { state, startResearch, reset };
}

