      "We recommend a BUY rating for Apple Inc. with a 12-month price target of $260, representing approximately 10.7% upside from current levels. Our thesis is anchored in Apple's unmatched ecosystem moat, accelerating services growth, and the upcoming AI-driven product cycle refresh that should drive both unit growth and average selling price expansion.\n\nThe risk-reward profile is attractive at current levels, with the services segment providing increasingly predictable recurring revenue while hardware innovation continues to drive upgrade cycles. Despite regulatory headwinds, Apple's financial strength and brand loyalty provide a margin of safety that justifies the premium valuation.",
    generatedAt: new Date().toISOString(),
  };
}

export function useResearch() {
  const [state, setState] = useState<ResearchState>({
    status: "idle",
    agents: [],
    report: null,
    error: null,
  });

  const timersRef = useRef<NodeJS.Timeout[]>([]);

  const clearAllTimers = useCallback(() => {
    timersRef.current.forEach(clearTimeout);
    timersRef.current = [];
  }, []);

  const startResearch = useCallback(
    (query: string) => {
      clearAllTimers();

      // Reset to researching state
      setState({
        status: "researching",
        agents: initialAgents.map((a) => ({ ...a, status: "idle", progress: 0 })),
        report: null,
        error: null,
      });

      // Simulate each agent running with staggered starts
      const agentCount = initialAgents.length;
      const agentDuration = 2000; // 2 seconds per agent
      const staggerDelay = 500; // 500ms between agent starts
      const progressInterval = 100; // Update progress every 100ms

      for (let i = 0; i < agentCount; i++) {
        const agentStartDelay = i * staggerDelay;

        // Set agent to running
        const startTimer = setTimeout(() => {
          setState((prev) => ({
            ...prev,
            agents: prev.agents.map((a, idx) =>
              idx === i ? { ...a, status: "running" as const, progress: 0 } : a
            ),
          }));
        }, agentStartDelay);
        timersRef.current.push(startTimer);

        // Increment progress
        const steps = agentDuration / progressInterval;
        for (let step = 1; step <= steps; step++) {
          const progressTimer = setTimeout(() => {
            const progress = Math.min(Math.round((step / steps) * 100), 100);
            setState((prev) => ({
              ...prev,
              agents: prev.agents.map((a, idx) =>
                idx === i ? { ...a, progress } : a
              ),
            }));
          }, agentStartDelay + step * progressInterval);
          timersRef.current.push(progressTimer);
        }

        // Set agent to completed
        const completeTimer = setTimeout(() => {
          setState((prev) => ({
            ...prev,
            agents: prev.agents.map((a, idx) =>
              idx === i ? { ...a, status: "completed" as const, progress: 100 } : a
            ),
          }));
        }, agentStartDelay + agentDuration);
        timersRef.current.push(completeTimer);
      }

      // All agents done → show report
      const totalTime = (agentCount - 1) * staggerDelay + agentDuration + 1000;
      const reportTimer = setTimeout(() => {
        setState((prev) => ({
          ...prev,
          status: "completed",
          report: getMockReport(),
        }));
      }, totalTime);
      timersRef.current.push(reportTimer);
    },
    [clearAllTimers]
  );

  const reset = useCallback(() => {
    clearAllTimers();
    setState({
      status: "idle",
      agents: [],
      report: null,
      error: null,
    });
  }, [clearAllTimers]);

  return { state, startResearch, reset };
}

