import { BaseMessage } from "@langchain/core/messages";
import { ResearchReport, CompanyData } from "../../types";

export interface AgentState {
  ticker: string;

  // Accumulated data
  companyOverview?: {
    name: string;
    sector: string;
    industry: string;
    description: string;
  };

  financialData?: {
    marketCap: number;
    currentPrice: number;
    priceChange: number;
    priceChangePercent: number;
    financialScore: number;
    growthScore: number;
    rawAnalysis: string;
  };

  newsData?: {
    sentimentScore: number;
    positiveDevelopments: string[];
    negativeDevelopments: string[];
    sources: string[];
  };

  riskData?: {
    riskScore: number;
    opportunities: string[];
    risks: string[];
  };

  decisionData?: {
    recommendation: "STRONG BUY" | "BUY" | "HOLD" | "SELL" | "STRONG SELL";
    confidence: number;
    overallScore: number;
    reasoning: string;
  };

  finalReport?: ResearchReport;
  messages: BaseMessage[];
  error?: string;
}

import { ChatGoogleGenerativeAI } from "@langchain/google-genai";

export const getGeminiModel = (temperature = 0.2) => {
  return new ChatGoogleGenerativeAI({
    modelName: "gemini-2.5-pro", 
    maxOutputTokens: 2048,
    temperature,
    apiKey: process.env.GOOGLE_API_KEY || "dummy-key",
  });
};

import { AgentState } from "../state";
import { getGeminiModel } from "../llm";
import { SystemMessage, HumanMessage } from "@langchain/core/messages";
import { StructuredOutputParser } from "langchain/output_parsers";
import { z } from "zod";
import yahooFinance from "yahoo-finance2";
import { ResearchReport } from "../../types";

export const researchAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  const parser = StructuredOutputParser.fromZodSchema(z.object({
    name: z.string(),
    sector: z.string(),
    industry: z.string(),
    description: z.string()
  }));

  const response = await getGeminiModel(0.1).invoke([
    new SystemMessage("Extract company overview details. Use the exact ticker symbol to identify the company."),
    new HumanMessage(`Ticker: ${state.ticker}\n\n${parser.getFormatInstructions()}`)
  ]);
  const result = await parser.parse(response.content as string);
  return { companyOverview: result };
};

export const financialAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  yahooFinance.suppressNotices(['yahooSurvey']);
  const quote = await yahooFinance.quote(state.ticker);

  const parser = StructuredOutputParser.fromZodSchema(z.object({
    financialScore: z.number().min(0).max(100),
    growthScore: z.number().min(0).max(100),
    rawAnalysis: z.string()
  }));

  const response = await getGeminiModel(0.2).invoke([
    new SystemMessage("Analyze financial health and growth. Generate scores (0-100)."),
    new HumanMessage(`Ticker: ${state.ticker}\nMarket Cap: ${quote.marketCap}\nPE: ${quote.forwardPE}\n\n${parser.getFormatInstructions()}`)
  ]);
  const result = await parser.parse(response.content as string);

  return {
    financialData: {
      marketCap: quote.marketCap || 0,
      currentPrice: quote.regularMarketPrice || 0,
      priceChange: quote.regularMarketChange || 0,
      priceChangePercent: quote.regularMarketChangePercent || 0,
      ...result
    }
  };
};

export const newsAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  const parser = StructuredOutputParser.fromZodSchema(z.object({
    sentimentScore: z.number().min(0).max(100),
    positiveDevelopments: z.array(z.string()),
    negativeDevelopments: z.array(z.string()),
    sources: z.array(z.string())
  }));

  // Simulate or fetch news. Without a reliable free News API here, we use Gemini's internal knowledge of recent events
  const response = await getGeminiModel(0.3).invoke([
    new SystemMessage("Analyze recent news sentiment for the company. Provide a score (0-100) and list positive/negative developments and assumed sources (e.g., Bloomberg, Reuters)."),
    new HumanMessage(`Analyze news for ${state.companyOverview?.name || state.ticker}\n\n${parser.getFormatInstructions()}`)
  ]);
  const result = await parser.parse(response.content as string);
  return { newsData: result };
};

export const riskAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  const parser = StructuredOutputParser.fromZodSchema(z.object({
    riskScore: z.number().min(0).max(100).describe("0 = High Risk, 100 = Low Risk (Safe)"),
    opportunities: z.array(z.string()),
    risks: z.array(z.string())
  }));

  const response = await getGeminiModel(0.2).invoke([
    new SystemMessage("Analyze market, regulatory, and competitive risks vs opportunities."),
    new HumanMessage(`Context: ${state.companyOverview?.name}, Negatives: ${state.newsData?.negativeDevelopments.join()}.\n\n${parser.getFormatInstructions()}`)
  ]);
  const result = await parser.parse(response.content as string);
  return { riskData: result };
};

export const decisionAgent = async (state: AgentState): Promise<Partial<AgentState>> => {
  const parser = StructuredOutputParser.fromZodSchema(z.object({
    recommendation: z.enum(["STRONG BUY", "BUY", "HOLD", "SELL", "STRONG SELL"]),
    confidence: z.number().min(0).max(100),
    overallScore: z.number().min(0).max(100),
    reasoning: z.string()
  }));

  const response = await getGeminiModel(0.2).invoke([
    new SystemMessage("Synthesize all data into a final recommendation and reasoning."),
    new HumanMessage(`Ticker: ${state.ticker}\nFinScore: ${state.financialData?.financialScore}\nGrowthScore: ${state.financialData?.growthScore}\nSentimentScore: ${state.newsData?.sentimentScore}\nRiskScore: ${state.riskData?.riskScore}\n\n${parser.getFormatInstructions()}`)
  ]);
  const result = await parser.parse(response.content as string);

  const finalReport: ResearchReport = {
    company: {
      name: state.companyOverview!.name,
      ticker: state.ticker,
      sector: state.companyOverview!.sector,
      industry: state.companyOverview!.industry,
      marketCap: state.financialData!.marketCap,
      currentPrice: state.financialData!.currentPrice,
      priceChange: state.financialData!.priceChange,
      priceChangePercent: state.financialData!.priceChangePercent,
    },
    financialScore: state.financialData!.financialScore,
    growthScore: state.financialData!.growthScore,
    sentimentScore: state.newsData!.sentimentScore,
    riskScore: state.riskData!.riskScore,
    overallScore: result.overallScore,
    recommendation: result.recommendation,
    confidence: result.confidence,
    reasoning: result.reasoning,
    opportunities: state.riskData!.opportunities,
    risks: state.riskData!.risks,
    sources: state.newsData!.sources,
  };

  return { decisionData: result, finalReport };
};

import { StateGraph, START, END } from "@langchain/langgraph";
import { AgentState } from "./state";
import { researchAgent, financialAgent, newsAgent, riskAgent, decisionAgent } from "./agents";

const channels = {
  ticker: { value: (x: string, y: string) => y ?? x, default: () => "" },
  companyOverview: { value: (x: any, y: any) => y ?? x },
  financialData: { value: (x: any, y: any) => y ?? x },
  newsData: { value: (x: any, y: any) => y ?? x },
  riskData: { value: (x: any, y: any) => y ?? x },
  decisionData: { value: (x: any, y: any) => y ?? x },
  finalReport: { value: (x: any, y: any) => y ?? x },
  messages: { value: (x: any[], y: any[]) => x.concat(y ?? []), default: () => [] },
  error: { value: (x: string, y: string) => y ?? x }
};

const workflow = new StateGraph<AgentState>({ channels: channels as any })
  .addNode("researchAgent", researchAgent)
  .addNode("financialAgent", financialAgent)
  .addNode("newsAgent", newsAgent)
  .addNode("riskAgent", riskAgent)
  .addNode("decisionAgent", decisionAgent)

  .addEdge(START, "researchAgent")
  .addConditionalEdges("researchAgent", (s) => s.error ? END : "financialAgent")
  .addConditionalEdges("financialAgent", (s) => s.error ? END : "newsAgent")
  .addConditionalEdges("newsAgent", (s) => s.error ? END : "riskAgent")
  .addConditionalEdges("riskAgent", (s) => s.error ? END : "decisionAgent")
  .addEdge("decisionAgent", END);

export const app = workflow.compile();

import { NextResponse } from "next/server";
import { app } from "@/lib/langgraph/graph";

export const maxDuration = 300; 

export async function POST(request: Request) {
  try {
    const { ticker } = await request.json();
    if (!ticker) return NextResponse.json({ error: "Ticker is required" }, { status: 400 });

    const finalState = await app.invoke({ ticker: ticker.toUpperCase(), messages: [] });

    if (finalState.error) {
      return NextResponse.json({ error: finalState.error }, { status: 500 });
    }

    return NextResponse.json(finalState.finalReport);

  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

"use client";

import { useState, useCallback, useRef } from "react";
import type { ResearchState, AgentProgress } from "@/lib/types";

const initialAgents: AgentProgress[] = [
  { name: "Research Agent", status: "idle", description: "Analyzing company overview, industry, and competitors", progress: 0, icon: "Search" },
  { name: "Financial Analyst", status: "idle", description: "Evaluating revenue growth, profitability, and debt", progress: 0, icon: "TrendingUp" },
  { name: "Sentiment Analyst", status: "idle", description: "Scanning news and market sentiment", progress: 0, icon: "Newspaper" },
  { name: "Risk Analyst", status: "idle", description: "Evaluating market, competition, and regulatory risks", progress: 0, icon: "ShieldAlert" },
  { name: "Investment Decision Agent", status: "idle", description: "Synthesizing data for final recommendation", progress: 0, icon: "Lightbulb" }
];

export function useResearch() {
  const [state, setState] = useState<ResearchState>({ status: "idle", agents: [], report: null, error: null });
  const timersRef = useRef<NodeJS.Timeout[]>([]);

  const clearAllTimers = useCallback(() => {
    timersRef.current.forEach(clearTimeout);
    timersRef.current = [];
  }, []);

  const startResearch = useCallback(async (query: string) => {
    clearAllTimers();
    setState({ status: "researching", agents: initialAgents.map(a => ({ ...a, status: "idle", progress: 0 })), report: null, error: null });

    for (let i = 0; i < initialAgents.length; i++) {
      timersRef.current.push(setTimeout(() => {
        setState(prev => ({ ...prev, agents: prev.agents.map((a, idx) => idx === i ? { ...a, status: "running" as const, progress: 10 } : a) }));
      }, i * 1500));

      timersRef.current.push(setInterval(() => {
        setState(prev => {
          const current = prev.agents[i];
          if (current.status === "running" && current.progress < 90) {
            return { ...prev, agents: prev.agents.map((a, idx) => idx === i ? { ...a, progress: a.progress + 5 } : a) };
          }
          return prev;
        });
      }, 800));
    }

    try {
      const response = await fetch("/api/research", {
        method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ ticker: query }),
      });
      if (!response.ok) throw new Error("Failed to fetch research report.");
      const report = await response.json();

      clearAllTimers();
      setState(prev => ({ ...prev, status: "completed", agents: prev.agents.map(a => ({ ...a, status: "completed", progress: 100 })), report, error: null }));
    } catch (error: any) {
      clearAllTimers();
      setState(prev => ({ ...prev, status: "error", agents: prev.agents.map(a => ({ ...a, status: "failed" })), error: error.message }));
    }
  }, [clearAllTimers]);

  const reset = useCallback(() => {
    clearAllTimers();
    setState({ status: "idle", agents: [], report: null, error: null });
  }, [clearAllTimers]);

  return { state, startResearch, reset };
}

